-- ============================================================================
-- V8: AI Prediction Tables — Waste predictions and historical data
-- AI Food Waste Redistribution Platform
-- ============================================================================

-- ============================================================================
-- Waste predictions generated by the ML model
-- ============================================================================
CREATE TABLE waste_predictions (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    restaurant_id UUID NOT NULL REFERENCES restaurants(id) ON DELETE CASCADE,
    predicted_date DATE NOT NULL,
    predicted_waste_kg DOUBLE PRECISION NOT NULL,
    actual_waste_kg DOUBLE PRECISION,
    confidence DOUBLE PRECISION CHECK (confidence >= 0 AND confidence <= 1),
    category VARCHAR(50),
    factors JSONB,
    model_version VARCHAR(50),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- ============================================================================
-- Historical waste data used to train predictions
-- ============================================================================
CREATE TABLE waste_history (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    restaurant_id UUID NOT NULL REFERENCES restaurants(id) ON DELETE CASCADE,
    date DATE NOT NULL,
    waste_kg DOUBLE PRECISION NOT NULL,
    category VARCHAR(50),
    day_of_week INTEGER CHECK (day_of_week >= 0 AND day_of_week <= 6),
    month INTEGER CHECK (month >= 1 AND month <= 12),
    is_holiday BOOLEAN DEFAULT FALSE,
    weather_condition VARCHAR(50),
    special_event VARCHAR(255),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- ============================================================================
-- Indexes
-- ============================================================================
-- waste_predictions
CREATE INDEX idx_waste_predictions_restaurant_id ON waste_predictions(restaurant_id);
CREATE INDEX idx_waste_predictions_predicted_date ON waste_predictions(predicted_date);
CREATE INDEX idx_waste_predictions_model_version ON waste_predictions(model_version);
CREATE UNIQUE INDEX idx_waste_predictions_restaurant_date_cat ON waste_predictions(restaurant_id, predicted_date, category);

-- waste_history
CREATE INDEX idx_waste_history_restaurant_id ON waste_history(restaurant_id);
CREATE INDEX idx_waste_history_date ON waste_history(date);
CREATE INDEX idx_waste_history_category ON waste_history(category);
CREATE INDEX idx_waste_history_day_of_week ON waste_history(day_of_week);
CREATE UNIQUE INDEX idx_waste_history_restaurant_date_cat ON waste_history(restaurant_id, date, category);
